import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#141414', card: '#1a1a1a', border: '#2a2a2a',
  text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  blue: '#38bdf8', green: '#4ade80', purple: '#a78bfa',
  yellow: '#fbbf24', pink: '#f472b6', orange: '#fb923c', red: '#f87171',
};

const CLASS0 = '#38bdf8';
const CLASS1 = '#f472b6';

const DATA_X = [
  [1, 3], [2, 5], [3, 2], [4, 4], [5, 1], [6, 6], [7, 3], [8, 5]
];
const DATA_Y = [0, 0, 0, 0, 1, 1, 1, 1];
const N = DATA_X.length;

function gini(labels) {
  if (labels.length === 0) return 0;
  const p = labels.filter(l => l === 1).length / labels.length;
  return 1 - p * p - (1 - p) * (1 - p);
}

function computeSplit(featureVals, labels, t) {
  const lIdx = [];
  const rIdx = [];
  featureVals.forEach((v, i) => {
    if (v <= t) lIdx.push(i);
    else rIdx.push(i);
  });
  const lL = lIdx.map(i => labels[i]);
  const rL = rIdx.map(i => labels[i]);
  const lG = gini(lL);
  const rG = gini(rL);
  const wG = (lL.length * lG + rL.length * rG) / labels.length;
  return { leftLabels: lL, rightLabels: rL, leftGini: lG, rightGini: rG, weightedGini: wG };
}

export default function App() {
  const [feat, setFeat] = useState(0);
  const [thresh, setThresh] = useState(4.5);
  const [playing, setPlaying] = useState(false);
  const [playIdx, setPlayIdx] = useState(-1);
  const svgRef = useRef(null);
  const dragging = useRef(false);

  const fVals = DATA_X.map(r => r[feat]);
  const uVals = useMemo(() => [...new Set(fVals)].sort((a, b) => a - b), [feat]);
  const minV = Math.min(...fVals) - 1;
  const maxV = Math.max(...fVals) + 1;

  const split = useMemo(() => computeSplit(fVals, DATA_Y, thresh), [fVals, thresh]);

  const allSplits = useMemo(() => {
    return uVals.map(t => {
      const s = computeSplit(fVals, DATA_Y, t);
      return { threshold: t, weightedGini: s.weightedGini };
    });
  }, [fVals, uVals]);

  const bestForFeature = useMemo(() => {
    return allSplits.reduce((b, s) => s.weightedGini < b.weightedGini ? s : b, allSplits[0]);
  }, [allSplits]);

  const overallBest = useMemo(() => {
    let best = { feature: 0, threshold: 0, gini: Infinity };
    for (let f = 0; f < DATA_X[0].length; f++) {
      const fv = DATA_X.map(r => r[f]);
      const uv = [...new Set(fv)].sort((a, b) => a - b);
      for (const t of uv) {
        const s = computeSplit(fv, DATA_Y, t);
        if (s.weightedGini < best.gini) {
          best = { feature: f, threshold: t, gini: s.weightedGini };
        }
      }
    }
    return best;
  }, []);

  const playSeq = useMemo(() => {
    const seq = [];
    for (let f = 0; f < 2; f++) {
      const fv = DATA_X.map(r => r[f]);
      const uv = [...new Set(fv)].sort((a, b) => a - b);
      for (const t of uv) seq.push({ feature: f, threshold: t });
    }
    return seq;
  }, []);

  useEffect(() => {
    if (!playing) return;
    const next = playIdx + 1;
    if (next >= playSeq.length) {
      setPlaying(false);
      setFeat(overallBest.feature);
      setThresh(overallBest.threshold);
      return;
    }
    const timer = setTimeout(() => {
      setPlayIdx(next);
      setFeat(playSeq[next].feature);
      setThresh(playSeq[next].threshold);
    }, 500);
    return () => clearTimeout(timer);
  }, [playing, playIdx, playSeq, overallBest]);

  const startPlay = () => {
    setPlayIdx(-1);
    setPlaying(true);
  };

  const resetAll = () => {
    setPlaying(false);
    setPlayIdx(-1);
    setFeat(0);
    setThresh(4.5);
  };

  const svgW = 540, svgH = 120;
  const padL = 35, padR = 15;
  const plotW = svgW - padL - padR;
  const toSvgX = (v) => padL + ((v - minV) / (maxV - minV)) * plotW;
  const fromSvgX = (px) => minV + ((px - padL) / plotW) * (maxV - minV);

  const handlePointerDown = (e) => {
    dragging.current = true;
    updateThresh(e);
  };

  const updateThresh = useCallback((e) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rect = svg.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const x = clientX - rect.left;
    const val = fromSvgX(x * (svgW / rect.width));
    setThresh(Math.max(minV + 0.2, Math.min(maxV - 0.2, Math.round(val * 10) / 10)));
  }, [minV, maxV, svgW, padL, plotW]);

  const handlePointerMove = useCallback((e) => {
    if (!dragging.current) return;
    e.preventDefault();
    updateThresh(e);
  }, [updateThresh]);

  const handlePointerUp = () => { dragging.current = false; };

  useEffect(() => {
    window.addEventListener('mousemove', handlePointerMove);
    window.addEventListener('mouseup', handlePointerUp);
    window.addEventListener('touchmove', handlePointerMove, { passive: false });
    window.addEventListener('touchend', handlePointerUp);
    return () => {
      window.removeEventListener('mousemove', handlePointerMove);
      window.removeEventListener('mouseup', handlePointerUp);
      window.removeEventListener('touchmove', handlePointerMove);
      window.removeEventListener('touchend', handlePointerUp);
    };
  }, [handlePointerMove]);

  const pointGroups = useMemo(() => {
    const groups = {};
    fVals.forEach((v, i) => {
      if (!groups[v]) groups[v] = [];
      groups[v].push(i);
    });
    return groups;
  }, [fVals]);

  const pointPositions = useMemo(() => {
    const pos = [];
    Object.entries(pointGroups).forEach(([val, indices]) => {
      const n = indices.length;
      indices.forEach((idx, k) => {
        const yOff = n === 1 ? 0 : (k - (n - 1) / 2) * 22;
        pos.push({ idx, x: toSvgX(Number(val)), y: 55 + yOff, val: Number(val), cls: DATA_Y[idx] });
      });
    });
    return pos;
  }, [pointGroups, feat, minV, maxV]);

  const threshX = toSvgX(thresh);

  const lc0 = split.leftLabels.filter(l => l === 0).length;
  const lc1 = split.leftLabels.filter(l => l === 1).length;
  const rc0 = split.rightLabels.filter(l => l === 0).length;
  const rc1 = split.rightLabels.filter(l => l === 1).length;

  const isAtBest = Math.abs(split.weightedGini - bestForFeature.weightedGini) < 0.001;
  const isGlobalBest = feat === overallBest.feature && Math.abs(split.weightedGini - overallBest.gini) < 0.001;

  let insight = '';
  if (isGlobalBest && overallBest.gini < 0.001) {
    insight = 'Perfect split found! Both leaves are pure (Gini = 0). This is the best possible split across all features.';
  } else if (isGlobalBest) {
    insight = 'This is the global best split across all features!';
  } else if (isAtBest && feat !== overallBest.feature) {
    insight = 'Best for this feature, but Feature ' + overallBest.feature + ' at threshold ' + overallBest.threshold + ' gives lower Gini (' + overallBest.gini.toFixed(3) + '). Try switching!';
  } else if (split.weightedGini > 0.48) {
    insight = 'Very high Gini - this split barely separates the classes. The groups are nearly as mixed as the original data.';
  } else if (split.weightedGini < 0.15 && split.weightedGini > 0.001) {
    insight = 'Good split! Low Gini means the groups are mostly pure. But can you find an even better one?';
  } else {
    insight = 'Drag the threshold to minimize weighted Gini. Best for Feature ' + feat + ': threshold = ' + bestForFeature.threshold + ' (Gini = ' + bestForFeature.weightedGini.toFixed(3) + ').';
  }

  const giniColor = split.weightedGini < 0.01 ? theme.green : split.weightedGini < 0.3 ? theme.yellow : theme.orange;

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', padding: '16px 16px', background: theme.bg, minHeight: '100vh', fontFamily: "'Inter', sans-serif", color: theme.text }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: 17, fontWeight: 700, letterSpacing: '-0.02em' }}>Gini Split Finder</div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={startPlay} disabled={playing} style={{ background: playing ? theme.border : theme.purple, border: 'none', color: theme.text, borderRadius: 6, padding: '5px 12px', fontSize: 12, fontWeight: 600, cursor: playing ? 'default' : 'pointer', opacity: playing ? 0.5 : 1 }}>
            {playing ? 'Scanning...' : 'Scan All'}
          </button>
          <button onClick={resetAll} style={{ background: theme.card, border: '1px solid ' + theme.border, color: theme.muted, borderRadius: 6, padding: '5px 10px', fontSize: 12, cursor: 'pointer' }}>Reset</button>
        </div>
      </div>

      {/* Feature tabs */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        {[0, 1].map(f => {
          const active = feat === f;
          const isBestF = f === overallBest.feature;
          return (
            <button key={f} onClick={() => { if (!playing) setFeat(f); }} style={{
              flex: 1, padding: '7px 0', borderRadius: 8, border: active ? '2px solid ' + theme.purple : '1px solid ' + theme.border,
              background: active ? '#1e1533' : theme.surface, color: active ? theme.purple : theme.muted,
              fontSize: 13, fontWeight: active ? 700 : 500, cursor: playing ? 'default' : 'pointer', transition: 'all 0.2s',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6
            }}>
              Feature {f}
              {isBestF && <span style={{ fontSize: 9, background: theme.green + '22', color: theme.green, padding: '1px 5px', borderRadius: 4 }}>best</span>}
            </button>
          );
        })}
      </div>

      {/* Main SVG - Number line */}
      <div style={{ background: theme.surface, borderRadius: 12, padding: '8px 4px 2px', marginBottom: 10, border: '1px solid ' + theme.border }}>
        <svg ref={svgRef} viewBox={'0 0 ' + svgW + ' ' + svgH} style={{ width: '100%', height: 'auto', cursor: 'ew-resize', display: 'block', userSelect: 'none' }}
          onMouseDown={handlePointerDown} onTouchStart={handlePointerDown}>
          {/* Left region */}
          <rect x={padL} y={10} width={Math.max(0, threshX - padL)} height={100} fill={CLASS0} opacity={0.06} rx={4} />
          {/* Right region */}
          <rect x={threshX} y={10} width={Math.max(0, svgW - padR - threshX)} height={100} fill={CLASS1} opacity={0.06} rx={4} />

          {/* Axis */}
          <line x1={padL} y1={95} x2={svgW - padR} y2={95} stroke={theme.border} strokeWidth={1} />
          {uVals.map(v => (
            <g key={v}>
              <line x1={toSvgX(v)} y1={92} x2={toSvgX(v)} y2={98} stroke={theme.dim} strokeWidth={1} />
              <text x={toSvgX(v)} y={110} textAnchor="middle" fill={theme.dim} fontSize={10} fontFamily="monospace">{v}</text>
            </g>
          ))}

          {/* Best threshold marker */}
          <line x1={toSvgX(bestForFeature.threshold)} y1={93} x2={toSvgX(bestForFeature.threshold)} y2={97} stroke={theme.green} strokeWidth={3} />
          <text x={toSvgX(bestForFeature.threshold)} y={90} textAnchor="middle" fill={theme.green} fontSize={8} fontFamily="monospace">best</text>

          {/* Data points */}
          {pointPositions.map((p) => (
            <g key={p.idx}>
              <circle cx={p.x} cy={p.y} r={13} fill={p.cls === 0 ? CLASS0 : CLASS1} opacity={0.15} />
              <circle cx={p.x} cy={p.y} r={10} fill={p.cls === 0 ? CLASS0 : CLASS1} opacity={0.9} />
              <text x={p.x} y={p.y + 4} textAnchor="middle" fill={'#fff'} fontSize={10} fontWeight={700} fontFamily="monospace">{p.cls}</text>
            </g>
          ))}

          {/* Threshold line */}
          <line x1={threshX} y1={12} x2={threshX} y2={98} stroke={theme.yellow} strokeWidth={2} strokeDasharray="4,3" />
          {/* Threshold handle */}
          <polygon points={(threshX - 8) + ',10 ' + (threshX + 8) + ',10 ' + threshX + ',22'} fill={theme.yellow} />
          <text x={threshX} y={7} textAnchor="middle" fill={theme.yellow} fontSize={11} fontWeight={700} fontFamily="monospace">
            {'<= ' + thresh.toFixed(1)}
          </text>
        </svg>
      </div>

      {/* Split details */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        {/* Left panel */}
        <div style={{ flex: 1, background: theme.surface, borderRadius: 10, padding: '10px 12px', border: '1px solid ' + theme.border }}>
          <div style={{ fontSize: 11, color: theme.muted, marginBottom: 6, display: 'flex', justifyContent: 'space-between' }}>
            <span>Left (x {'<='} {thresh.toFixed(1)})</span>
            <span style={{ fontWeight: 700 }}>n={split.leftLabels.length}</span>
          </div>
          <div style={{ display: 'flex', gap: 4, marginBottom: 6 }}>
            <div style={{ flex: lc0 || 0.1, height: 14, background: CLASS0, borderRadius: 3, transition: 'flex 0.2s' }} />
            <div style={{ flex: lc1 || 0.1, height: 14, background: CLASS1, borderRadius: 3, transition: 'flex 0.2s' }} />
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.muted, marginBottom: 4 }}>
            <span style={{ color: CLASS0 }}>{lc0} class-0</span>
            <span style={{ color: CLASS1 }}>{lc1} class-1</span>
          </div>
          <div style={{ fontSize: 13, fontWeight: 700, fontFamily: 'monospace', color: theme.text }}>
            Gini = {split.leftGini.toFixed(3)}
          </div>
        </div>

        {/* Center weighted Gini */}
        <div style={{ width: 90, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', background: theme.card, borderRadius: 10, padding: '8px 4px', border: '2px solid ' + giniColor + '44' }}>
          <div style={{ fontSize: 9, color: theme.dim, marginBottom: 2, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Weighted</div>
          <div style={{ fontSize: 9, color: theme.dim, marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Gini</div>
          <div style={{ fontSize: 20, fontWeight: 800, fontFamily: 'monospace', color: giniColor, transition: 'color 0.3s' }}>
            {split.weightedGini.toFixed(3)}
          </div>
          {isAtBest && <div style={{ fontSize: 8, color: theme.green, marginTop: 3, fontWeight: 700 }}>MINIMUM</div>}
        </div>

        {/* Right panel */}
        <div style={{ flex: 1, background: theme.surface, borderRadius: 10, padding: '10px 12px', border: '1px solid ' + theme.border }}>
          <div style={{ fontSize: 11, color: theme.muted, marginBottom: 6, display: 'flex', justifyContent: 'space-between' }}>
            <span>Right (x {'>'} {thresh.toFixed(1)})</span>
            <span style={{ fontWeight: 700 }}>n={split.rightLabels.length}</span>
          </div>
          <div style={{ display: 'flex', gap: 4, marginBottom: 6 }}>
            <div style={{ flex: rc0 || 0.1, height: 14, background: CLASS0, borderRadius: 3, transition: 'flex 0.2s' }} />
            <div style={{ flex: rc1 || 0.1, height: 14, background: CLASS1, borderRadius: 3, transition: 'flex 0.2s' }} />
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.muted, marginBottom: 4 }}>
            <span style={{ color: CLASS0 }}>{rc0} class-0</span>
            <span style={{ color: CLASS1 }}>{rc1} class-1</span>
          </div>
          <div style={{ fontSize: 13, fontWeight: 700, fontFamily: 'monospace', color: theme.text }}>
            Gini = {split.rightGini.toFixed(3)}
          </div>
        </div>
      </div>

      {/* Gini landscape */}
      <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 14px', marginBottom: 10, border: '1px solid ' + theme.border }}>
        <div style={{ fontSize: 10, color: theme.dim, marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Weighted Gini for each threshold (Feature {feat})</div>
        <div style={{ display: 'flex', alignItems: 'flex-end', gap: 3, height: 55 }}>
          {allSplits.map((s, i) => {
            const h = Math.max(2, (s.weightedGini / 0.5) * 50);
            const isActive = Math.abs(thresh - s.threshold) < 0.5;
            const isBest = Math.abs(s.weightedGini - bestForFeature.weightedGini) < 0.001;
            const barColor = isBest ? theme.green : isActive ? theme.yellow : theme.border;
            return (
              <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', cursor: 'pointer' }}
                onClick={() => { if (!playing) setThresh(s.threshold); }}>
                <div style={{ fontSize: 8, color: isActive ? theme.yellow : theme.dim, marginBottom: 2, fontFamily: 'monospace', transition: 'color 0.2s' }}>
                  {isActive ? s.weightedGini.toFixed(3) : ''}
                </div>
                <div style={{
                  width: '100%', maxWidth: 36, height: h, borderRadius: 3,
                  background: barColor, opacity: isActive ? 1 : 0.5,
                  transition: 'all 0.2s', border: isActive ? '1px solid ' + theme.yellow : 'none'
                }} />
                <div style={{ fontSize: 9, color: isActive ? theme.yellow : theme.dim, marginTop: 3, fontFamily: 'monospace', fontWeight: isActive ? 700 : 400 }}>
                  {s.threshold}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Formula */}
      <div style={{ background: theme.card, borderRadius: 8, padding: '8px 12px', marginBottom: 8, fontFamily: 'monospace', fontSize: 11, color: theme.muted, lineHeight: 1.7 }}>
        <span style={{ color: theme.dim }}>G = </span>
        <span style={{ color: CLASS0 }}>({split.leftLabels.length}/{N})</span>
        <span style={{ color: theme.dim }}> x </span>
        <span style={{ color: theme.text }}>{split.leftGini.toFixed(3)}</span>
        <span style={{ color: theme.dim }}> + </span>
        <span style={{ color: CLASS1 }}>({split.rightLabels.length}/{N})</span>
        <span style={{ color: theme.dim }}> x </span>
        <span style={{ color: theme.text }}>{split.rightGini.toFixed(3)}</span>
        <span style={{ color: theme.dim }}> = </span>
        <span style={{ color: giniColor, fontWeight: 700 }}>{split.weightedGini.toFixed(3)}</span>
      </div>

      {/* Insight */}
      <div style={{
        fontSize: 12, color: theme.muted, lineHeight: 1.6, padding: '8px 12px',
        borderLeft: '3px solid ' + (isGlobalBest ? theme.green : isAtBest ? theme.yellow : theme.border),
        transition: 'border-color 0.3s',
      }}>
        {insight}
      </div>
    </div>
  );
}
